// Devuelve la lista plana + añade flags útiles para el selector:
//   full              → promoción 100% llena (no se puede asignar)
//   manana_disponible → turno mañana con plazas libres
//   tarde_disponible  → turno tarde con plazas libres
const items = ($input.all() || []).map(i => i.json).filter(x => x && x.id);
const out = items.map(p => ({
  ...p,
  full: (p.libres_total || 0) <= 0,
  manana_disponible: (p.libres_manana || 0) > 0,
  tarde_disponible:  (p.libres_tarde  || 0) > 0
}));
return [{ json: { promociones: out } }];

// Validar y emitir el row APLANADO al raíz (para que Supabase upsert
// lo consuma con autoMapInputData sin interferir con 'action' ni 'row').
// Si hay error de validación, emitimos un item con bandera __error:true
// que el Formatear final detecta y devuelve el mensaje.
const raw = $input.first().json || {};
const b = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const action = String(b.action || 'create').toLowerCase();
const p = b.promocion || {};
if (!['create','update','delete','reactivar'].includes(action)) {
  return [{ json: { __error: true, __errores: ['action inválida: ' + action], __action: action } }];
}
const errores = [];
if (action === 'create' && (!p.nombre || !String(p.nombre).trim())) errores.push('nombre obligatorio');
if (action !== 'create' && !p.id) errores.push('id obligatorio para ' + action);
if (errores.length > 0) return [{ json: { __error: true, __errores: errores, __action: action } }];

const out = {};
if (action === 'create') {
  out.nombre = String(p.nombre).trim();
  if (p.descripcion != null)   out.descripcion   = String(p.descripcion);
  if (p.fecha_inicio)          out.fecha_inicio  = p.fecha_inicio;
  out.estado        = p.estado === 'cerrada' ? 'cerrada' : 'activa';
  out.plazas_manana = Number.isFinite(+p.plazas_manana) ? +p.plazas_manana : 8;
  out.plazas_tarde  = Number.isFinite(+p.plazas_tarde)  ? +p.plazas_tarde  : 8;
  if (p.created_by) out.created_by = String(p.created_by);
} else if (action === 'update') {
  out.id = p.id;
  if (p.nombre       !== undefined) out.nombre       = String(p.nombre).trim();
  if (p.descripcion  !== undefined) out.descripcion  = p.descripcion ? String(p.descripcion) : null;
  if (p.fecha_inicio !== undefined) out.fecha_inicio = p.fecha_inicio || null;
  if (p.estado       !== undefined) out.estado       = p.estado === 'cerrada' ? 'cerrada' : 'activa';
  if (p.plazas_manana !== undefined && Number.isFinite(+p.plazas_manana)) out.plazas_manana = +p.plazas_manana;
  if (p.plazas_tarde  !== undefined && Number.isFinite(+p.plazas_tarde))  out.plazas_tarde  = +p.plazas_tarde;
  out.updated_at = new Date().toISOString();
} else if (action === 'delete') {
  out.id = p.id; out.deleted_at = new Date().toISOString();
} else if (action === 'reactivar') {
  out.id = p.id; out.deleted_at = null;
}
return [{ json: out }];

// DIAGNOSTIC: volcamos la salida de Supabase UPSERT tal cual.
const items = $input.all() || [];
const errores = [];
let rows = [];
let cortoPreparar = false;
const _trace = items.map(i => { try { return { keys: Object.keys(i.json||{}), json: i.json }; } catch (_) { return '?'; } });
for (const it of items) {
  const j = it.json; if (!j) continue;
  if (j.__error) { cortoPreparar = true; (j.__errores||[]).forEach(e=>errores.push(e)); continue; }
  if (Array.isArray(j)) { rows = rows.concat(j); continue; }
  if (j.error) { errores.push(String(j.error.message || j.error)); continue; }
  if (j.code && j.message && !j.id) { errores.push(j.message + (j.details?' ('+j.details+')':'')); continue; }
  if (j.id) rows.push(j);
}
if (cortoPreparar) return [{ json: { success: false, errores, promocion: null, _trace } }];
if (rows.length === 0 && errores.length === 0) errores.push('UPSERT devolvió 0 filas');
return [{ json: {
  success: rows.length > 0,
  promocion: rows[0] || null,
  errores,
  _trace
} }];
